import{TMDB_IMG_BASE}from './config.js';import{getGlobalSettings}from './settings.js';import './tv.js';export function formatDate(dateStr){if(!dateStr)return "N/A";const isoMatch=dateStr.match(/^(\d{4})-(\d{2})-(\d{2})/);if(isoMatch){const year=parseInt(isoMatch[1],10);const month=parseInt(isoMatch[2],10)-1;const day=parseInt(isoMatch[3],10);const date=new Date(year,month,day);if(!isNaN(date.getTime())){const options={day:'numeric',month:'short',year:'numeric'};return date.toLocaleDateString('es-ES',options);}}const parts=dateStr.split('-');if(parts.length!==3)return dateStr;const date=new Date(parts[0],parts[1]-1,parts[2]);if(isNaN(date.getTime()))return dateStr;const options={day:'numeric',month:'short',year:'numeric'};return date.toLocaleDateString('es-ES',options);}export function formatYear(dateStr){if(!dateStr)return "";return dateStr.substring(0,4);}export function formatRuntime(minutes){if(!minutes)return "N/A";const hrs=Math.floor(minutes/60);const mins=minutes % 60;return hrs>0?`${hrs}h ${mins}min`:`${mins}min`;}export function formatRating(vote){if(vote===undefined||vote===null||isNaN(vote))return "0.0";return Number(vote).toFixed(1);}export function truncateText(text,maxLen){if(!text)return "";if(text.length<=maxLen)return text;return text.substring(0,maxLen).trim()+"...";}export function getRatingColor(score){if(score>=7)return '#2e7d32';if(score>=5)return '#f57f17';return '#E50914';}export function debounce(fn,ms){let timer;return function(...args){clearTimeout(timer);timer=setTimeout(()=>fn.apply(this,args),ms);};}export function throttle(fn,ms){let lastTime=0;return function(...args){const now=Date.now();if(now-lastTime>=ms){lastTime=now;fn.apply(this,args);}};}export function getYoutubeKey(videos){if(!videos||videos.length===0)return null;const trailer=videos.find(v=>v.site==='YouTube'&&(v.type==='Trailer'||v.name.toLowerCase().includes('trailer')||v.name.toLowerCase().includes('oficial')));if(trailer)return trailer.key;const ytVideo=videos.find(v=>v.site==='YouTube');return ytVideo?ytVideo.key:null;}export function buildTMDBImageURL(path,size='original'){if(!path){if(size.startsWith('w300')||size.startsWith('w780')||size.startsWith('w1280')){return 'assets/placeholder-backdrop.svg';}return 'assets/placeholder-poster.svg';}const base=`${TMDB_IMG_BASE}${size}${path}`;if(typeof window!=='undefined'){if(window._cvWebP===true){return base.replace('image.tmdb.org','wsrv.nl/?url=image.tmdb.org')+'&output=webp';}if(window._cvWebP===undefined){window._cvWebP=null;(async()=>{try{const blob=await fetch('data:image/webp;base64,UklGRlYAAABXRUJQVlA4IEoAAADQAQCdASoBAAEAAUAmJZQCdAEO/gcAAADRh5eMQqsAMi3P3gAA').then(r=>r.blob());window._cvWebP=blob.type==='image/webp';}catch{window._cvWebP=false;}})();}}return base;}export function getMediaType(item){if(!item)return 'movie';if(item.media_type)return item.media_type;if(item.first_air_date||item.name||item.number_of_seasons!==undefined)return 'tv';return 'movie';}export function navigateTo(page,params={}){const queryParams=new URLSearchParams(params);const queryString=queryParams.toString();const url=queryString?`${page}?${queryString}`:page;const overlay=document.querySelector('.page-transition-overlay');if(overlay){overlay.classList.remove('out');overlay.classList.add('in');setTimeout(()=>{window.location.href=url;},400);}else{window.location.href=url;}}export function initPageTransition(){const overlay=document.querySelector('.page-transition-overlay');if(overlay){overlay.classList.remove('in');overlay.classList.add('out');}(async()=>{try{const isMaintenancePage=window.location.pathname.includes('admin.html')||window.location.pathname.includes('login.html');const settings=await getGlobalSettings();if(settings?.maintenance_mode&&!isMaintenancePage){const{getCurrentUser}=await import('./auth.js');const userObj=await getCurrentUser().catch(()=>null);const isAdm=userObj?.profile?.is_admin===true;if(!isAdm){document.body.innerHTML=`<div style="position:fixed;inset:0;background:#090909;display:flex;flex-direction:column;align-items:center;justify-content:center;color:#fff;font-family:'Outfit',sans-serif;z-index:999999;text-align:center;padding:2rem;"><div style="font-size:4rem;margin-bottom:1.5rem;animation:pulse 2s infinite;">🛠️</div><h1 style="font-size:2rem;font-weight:800;margin-bottom:1rem;color:var(--accent-red,#E50914)">Mantenimiento Programado</h1><p style="color:#aaa;max-width:450px;line-height:1.6;font-size:0.95rem;">CineVerse se encuentra actualizando sus servidores para ofrecerte una mejor experiencia. Volvemos muy pronto.</p><div style="margin-top:2rem;height:1px;width:80px;background:rgba(255,255,255,0.1);"></div><p style="font-size:0.75rem;color:#444;margin-top:1rem;">CineVerse Tech Team</p></div>`;document.body.style.overflow='hidden';return;}}const pageName=window.location.pathname.split('/').pop().replace('.html','')||'index';const seo=settings?.seo_overrides?.[pageName];if(seo){if(seo.title)document.title=seo.title;const metaDesc=document.querySelector('meta[name="description"]');if(metaDesc&&seo.desc){metaDesc.setAttribute('content',seo.desc);}}}catch(e){console.warn('[PageTransition]Error checking maintenance/SEO:',e);}})();}export function getCurrentParams(){const searchParams=new URLSearchParams(window.location.search);const params={};for(const[key,value]of searchParams.entries()){params[key]=value;}return params;}export async function showToast(message,type='info'){try{const{toast}=await import('./components/toast.js');toast.show(message,type);}catch(error){console.error("Error al disparar el toast dinámico:",error);}}export const THEME_COLORS={red:{name:'Rojo CineVerse',accent:'#E50914',crimson:'#C1121F',ember:'#FF2D2D',dark:'#8B0000',glow:'rgba(229,9,20,0.35)',glowInt:'rgba(229,9,20,0.7)',border:'rgba(229,9,20,0.4)'},gold:{name:'Dorado Premium',accent:'#F5C518',crimson:'#D4A017',ember:'#FFD700',dark:'#9A7D0A',glow:'rgba(245,197,24,0.35)',glowInt:'rgba(245,197,24,0.7)',border:'rgba(245,197,24,0.4)'},blue:{name:'Azul Medianoche',accent:'#0079FF',crimson:'#0060CC',ember:'#3B9EFF',dark:'#003D80',glow:'rgba(0,121,255,0.35)',glowInt:'rgba(0,121,255,0.7)',border:'rgba(0,121,255,0.4)'},purple:{name:'Morado Fantasma',accent:'#8B5CF6',crimson:'#7C3AED',ember:'#A78BFA',dark:'#4C1D95',glow:'rgba(139,92,246,0.35)',glowInt:'rgba(139,92,246,0.7)',border:'rgba(139,92,246,0.4)'},green:{name:'Verde Esmeralda',accent:'#10B981',crimson:'#059669',ember:'#34D399',dark:'#065F46',glow:'rgba(16,185,129,0.35)',glowInt:'rgba(16,185,129,0.7)',border:'rgba(16,185,129,0.4)'},orange:{name:'Naranja Fuego',accent:'#F97316',crimson:'#C2410C',ember:'#FB923C',dark:'#7C2D12',glow:'rgba(249,115,22,0.35)',glowInt:'rgba(249,115,22,0.7)',border:'rgba(249,115,22,0.4)'},pink:{name:'Rosa Neón',accent:'#EC4899',crimson:'#BE185D',ember:'#F472B6',dark:'#831843',glow:'rgba(236,72,153,0.35)',glowInt:'rgba(236,72,153,0.7)',border:'rgba(236,72,153,0.4)'},cyan:{name:'Celeste Océano',accent:'#06B6D4',crimson:'#0E7490',ember:'#22D3EE',dark:'#164E63',glow:'rgba(6,182,212,0.35)',glowInt:'rgba(6,182,212,0.7)',border:'rgba(6,182,212,0.4)'},matrix:{name:'Cyber Matrix',accent:'#39FF14',crimson:'#008F11',ember:'#76FF03',dark:'#003B00',glow:'rgba(57,255,20,0.35)',glowInt:'rgba(57,255,20,0.7)',border:'rgba(57,255,20,0.4)'},wine:{name:'Vino Oscuro',accent:'#991B1B',crimson:'#7F1D1D',ember:'#EF4444',dark:'#450A0A',glow:'rgba(153,27,27,0.35)',glowInt:'rgba(153,27,27,0.7)',border:'rgba(153,27,27,0.4)'},coal:{name:'Carbón/Plata',accent:'#E2E8F0',crimson:'#94A3B8',ember:'#F8FAFC',dark:'#475569',glow:'rgba(226,232,240,0.35)',glowInt:'rgba(226,232,240,0.7)',border:'rgba(226,232,240,0.4)'},lavender:{name:'Lavanda Mística',accent:'#A855F7',crimson:'#7E22CE',ember:'#C084FC',dark:'#581C87',glow:'rgba(168,85,247,0.35)',glowInt:'rgba(168,85,247,0.7)',border:'rgba(168,85,247,0.4)'},yellow_neon:{name:'Amarillo Neón',accent:'#EAB308',crimson:'#A16207',ember:'#FDE047',dark:'#713F12',glow:'rgba(234,179,8,0.35)',glowInt:'rgba(234,179,8,0.7)',border:'rgba(234,179,8,0.4)'},amoled:{name:'AMOLED Negro Puro',accent:'#FFFFFF',crimson:'#CCCCCC',ember:'#F0F0F0',dark:'#111111',glow:'rgba(255,255,255,0.15)',glowInt:'rgba(255,255,255,0.4)',border:'rgba(255,255,255,0.25)'}};export function applyUserTheme(themeName){const theme=THEME_COLORS[themeName]||THEME_COLORS.red;const root=document.documentElement;root.style.setProperty('--accent-red',theme.accent);root.style.setProperty('--accent-crimson',theme.crimson);root.style.setProperty('--accent-ember',theme.ember);root.style.setProperty('--accent-dark-red',theme.dark);root.style.setProperty('--glow-red',theme.glow);root.style.setProperty('--glow-red-intense',theme.glowInt);root.style.setProperty('--border-red',theme.border);}export function protectWebCode(){const isLocal=window.location.hostname==='localhost'||window.location.hostname==='127.0.0.1';const isNativeApp=window.location.protocol==='file:'||(window.Capacitor&&window.Capacitor.isNativePlatform&&window.Capacitor.isNativePlatform())||navigator.userAgent.includes('Capacitor');if(isLocal||isNativeApp)return;document.addEventListener('contextmenu',(e)=>e.preventDefault());document.addEventListener('keydown',(e)=>{if(e.key==='F12'){e.preventDefault();return false;}if((e.ctrlKey||e.metaKey)&&((e.shiftKey&&(e.key==='I'||e.key==='i'||e.key==='J'||e.key==='j'||e.key==='C'||e.key==='c'))||(e.key==='U'||e.key==='u'||e.key==='S'||e.key==='s'||e.key==='P'||e.key==='p'))){e.preventDefault();return false;}if(e.metaKey&&e.altKey&&(e.key==='I'||e.key==='i'||e.key==='J'||e.key==='j'||e.key==='C'||e.key==='c')){e.preventDefault();return false;}});setInterval(()=>{const start=Date.now();debugger;const end=Date.now();if(end-start>100){document.body.innerHTML=`<div style="height:100vh;display:flex;flex-direction:column;align-items:center;justify-content:center;background:#050505;color:#fff;font-family:sans-serif;text-align:center;padding:2rem;"><h1 style="color:#e50914;font-size:2rem;margin-bottom:1rem;font-weight:700;">⚠️ ACCESO RESTRINGIDO</h1><p style="color:#a0aec0;font-size:0.95rem;max-width:400px;line-height:1.5;">La inspección de código y consola de desarrollador están desactivadas por motivos de seguridad en producción.</p></div>`;}},1000);}export function getCVLoader(text='Cargando...'){return `<div class="cv-loader" role="status" aria-label="${text}"><svg class="cv-loader__svg" viewBox="0 0 64 64" fill="none" xmlns="http://www.w3.org/2000/svg"><!--Cuerpo principal de la claqueta--><rect x="4" y="20" width="56" height="38" rx="3" fill="#1a1a2e" stroke="#e50914" stroke-width="2"/><!--Líneas de la claqueta--><line x1="4" y1="32" x2="60" y2="32" stroke="rgba(229,9,20,0.35)" stroke-width="1"/><line x1="4" y1="44" x2="60" y2="44" stroke="rgba(229,9,20,0.35)" stroke-width="1"/><!--Texto CINEVERSE en la claqueta--><text x="32" y="55" text-anchor="middle" font-family="monospace" font-size="5" fill="rgba(255,255,255,0.4)" letter-spacing="2">CINEVERSE</text><!--Brazo animado de la claqueta--><g class="cv-loader__arm"><rect x="4" y="10" width="56" height="11" rx="2" fill="#e50914"/><!--Franjas diagonales del brazo--><clipPath id="armClip"><rect x="4" y="10" width="56" height="11" rx="2"/></clipPath><g clip-path="url(#armClip)"><line x1="10" y1="10" x2="4" y2="21" stroke="#fff" stroke-width="2.5" stroke-opacity="0.2"/><line x1="20" y1="10" x2="14" y2="21" stroke="#fff" stroke-width="2.5" stroke-opacity="0.2"/><line x1="30" y1="10" x2="24" y2="21" stroke="#fff" stroke-width="2.5" stroke-opacity="0.2"/><line x1="40" y1="10" x2="34" y2="21" stroke="#fff" stroke-width="2.5" stroke-opacity="0.2"/><line x1="50" y1="10" x2="44" y2="21" stroke="#fff" stroke-width="2.5" stroke-opacity="0.2"/><line x1="60" y1="10" x2="54" y2="21" stroke="#fff" stroke-width="2.5" stroke-opacity="0.2"/></g></g><!--Bisagra--><circle cx="8" cy="20" r="3" fill="#e50914"/></svg>${text?`<span class="cv-loader__text">${text}</span>`:''}</div>`;}